import React, { useState } from "react";
import "./package.css";
import Book from "./book";
import Gallery from "./gallary";

// Import images for galleries
import img1 from "../Assets/img5.jpg";
import img2 from "../Assets/tent1.jpg";
import img3 from "../Assets/tent3.jpg";
import img4 from "../Assets/tent4.jpg";
import img5 from "../Assets/tent5.jpg";

const tentGallery = [
  { image: img1, className: "" },
  { image: img2, className: "" },
  { image: img5, className: "" },
  { image: img3, className: "tall" },
  { image: img4, className: "wide" },
];

const glamGallery = [
  { image: img1, stayType: "Glam Stay" },
  { image: img2, stayType: "Glam Stay" },
];

const domeGallery = [
  { image: img1, stayType: "Dome Stay" },
  { image: img2, stayType: "Dome Stay" },
];

function StayDetails({ stayType, onBack }) {
  const [currentGallery, setCurrentGallery] = useState([]);

  React.useEffect(() => {
    if (stayType === "Tent Stay") {
      setCurrentGallery(tentGallery);
    } else if (stayType === "Glam Stay") {
      setCurrentGallery(glamGallery);
    } else if (stayType === "Dome Stay") {
      setCurrentGallery(domeGallery);
    }
  }, [stayType]);

  return (
    <div>
      <button onClick={onBack} className="add-to-cart" style={{ marginBottom: "20px" }}>
        Back to Packages
      </button>
      <Book stayType={stayType} />
      <Gallery galleryItems={currentGallery} stayType={stayType} />
    </div>
  );
}

export default StayDetails;
